SELECT d.DEPTNO, d.ORG_NAME_LOCAL AS DISP_DEPT_NAME, d.PARENT_DEPT_NO, d.DEPT_LEVEL, m.MANAGE_NO, #{lockDate} AS LOCK_DATE, NVL(m.LOCK_ATTEN_FLAG, '0') AS LOCK_ATTEN_FLAG, NVL(m.LOCK_ATTEN_NIGHT_FLAG, '0') AS LOCK_ATTEN_NIGHT_FLAG, NVL(m.LOCK_OT_FLAG, '0') AS LOCK_OT_FLAG, NVL(m.LOCK_OT_NIGHT_FLAG, '0') AS LOCK_OT_NIGHT_FLAG, NVL(m.LOCK_ATTEN_EX_FLAG, '0') AS LOCK_ATTEN_EX_FLAG, NVL(m.LOCK_ATTEN_EX_NIGHT_FLAG, '0') AS LOCK_ATTEN_EX_NIGHT_FLAG, NVL(m.LOCK_ATTEN_ANNUAL_FLAG, '0') AS LOCK_ATTEN_ANNUAL_FLAG, NVL(m.LOCK_ATTEN_ANNUAL_NIGHT_FLAG, '0') AS LOCK_ATTEN_ANNUAL_NIGHT_FLAG, m.UPDATED_BY, m.UPDATE_DATE FROM HR_DEPARTMENT d LEFT JOIN AR_DEPARTMENT_MANAGE m ON d.DEPTNO = m.DEPT_NO AND m.LOCK_DATE = #{lockDate} AND m.CPNY_ID = #{cpnyId} WHERE d.ACTIVITY = 1 AND d.CPNY_ID = #{cpnyId}
AND d.DEPTNO IN
#{deptId}
ORDER BY d.DEPT_LEVEL ASC, d.DEPTNO ASC

SELECT COUNT(1)
FROM AR_DEPARTMENT_MANAGE
WHERE CPNY_ID = #{cpnyId}
  AND DEPT_NO = #{deptNo}
  AND LOCK_DATE = #{lockDate}
